202→/// Yields pre-computed boundary-value input vectors using pairwise coverage.
203→///
204→/// For each parameter position, every boundary value for that parameter's type
205→/// is paired with neutral defaults for all other parameters. This caps the
206→/// candidate count at `sum(boundaries_per_type_i)` instead of the cartesian
207→/// product. Delegates to [`generate_boundary_inputs`] for the actual generation.
208→pub struct BoundarySeeds {
209→    candidates: Vec<Vec<Value>>,
210→    cursor: usize,
211→}
212→
213→impl BoundarySeeds {
214→    pub fn new(params: &[ParamInfo]) -> Self {
215→        Self {
216→            candidates: generate_boundary_inputs(params),
217→            cursor: 0,
218→        }
219→    }
220→}
221→
222→impl InputStrategy for BoundarySeeds {
223→    fn next(&mut self, _ctx: &StrategyContext) -> Option<Vec<Value>> {
224→        if self.cursor < self.candidates.len() {
225→            let v = self.candidates[self.cursor].clone();
226→            self.cursor += 1;
227→            Some(v)
228→        } else {
229→            None
230→        }
231→    }
232→
233→    fn name(&self) -> &str {
234→        "boundary"
235→    }
236→
237→    fn estimated_size(&self) -> Option<u64> {
238→        Some(self.candidates.len() as u64)
239→    }
240→}
241→
242→// ---------------------------------------------------------------------------
243→// MetaConfig — controls the adaptive selection algorithm
244→// ---------------------------------------------------------------------------
245→
246→/// Configuration for the adaptive meta-strategy.
247→#[derive(Debug, Clone)]
248→pub struct MetaConfig {
249→    /// Sliding window size for outcome-based scoring.
250→    pub window_size: usize,
251→    /// Minimum candidates a strategy must supply before deprioritization.
252→    /// Clamped to `min(cold_start_threshold, estimated_size)` per strategy.
253→    pub cold_start_threshold: u64,
254→    /// Minimum allocation fraction for any non-exhausted strategy (range 0.01–0.05).
255→    pub floor: f64,
256→    /// When true, use adaptive scoring. When false (and no static_weights),
257→    /// use pure round-robin.
258→    pub adaptive: bool,
259→    /// Optional static weight distribution. Keys are strategy names, values
260→    /// are relative weights (normalized internally). Overrides adaptive scoring.
261→    pub static_weights: Option<Vec<(String, f64)>>,
262→}
263→
264→/// Sensible defaults: adaptive scoring, 100-element window, cold start of 20,
265→/// 2% floor, no static weights.
266→impl Default for MetaConfig {
