    fn boundary_seeds_unknown_type_yields_nothing() {
        let params = make_params(&[TypeInfo::Unknown]);
        let mut bs = BoundarySeeds::new(&params);
        let ctx = empty_ctx();
        assert_eq!(bs.estimated_size(), Some(0));
        assert!(bs.next(&ctx).is_none());
    }

